import { useGovernanceFeed } from "../hooks/use-governance-feed";

export function HomePage() {
  const { feed, isLoading, error, refresh } = useGovernanceFeed();

  return (
    <section className="home-page">
      <GovernanceFeed
        feed={feed}
        isLoading={isLoading}
        error={error}
        onRefresh={refresh}
      />
    </section>
  );
}

